const path = require('path')
const fs = require('fs')

function findScipTs() {
  const candidates = [
    path.join(process.cwd(), 'node_modules', '.bin', 'scip-typescript'),
    path.join(__dirname, '..', 'node_modules', '.bin', 'scip-typescript'),
  ]
  for (const p of candidates) {
    if (fs.existsSync(p)) return p
  }
  return 'scip-typescript'
}

function parseScipDocument(buffer) {
  const symbols = []
  const files = new Set()

  try {
    const data = buffer.toString('utf8')
    const lines = data.split('\n')
    for (const line of lines) {
      if (!line.trim()) continue
      try {
        const parsed = JSON.parse(line)
        if (parsed.uri) files.add(parsed.uri)
        if (parsed.symbol) {
          symbols.push({
            symbol: parsed.symbol,
            kind: parsed.kind || 'unknown',
            uri: parsed.uri || '',
            range: parsed.range || null,
            relationships: parsed.relationships || [],
            diagnostic: parsed.diagnostic || null,
          })
        }
      } catch {
        continue
      }
    }
  } catch {
    return { symbols: [], files: [] }
  }

  return { symbols, files: Array.from(files) }
}

function indexTypescript(targetDir, opts = {}) {
  const outPath = opts.outputPath || path.join(targetDir, 'index.scip')
  const timeout = opts.timeout || 120000
  const scipBin = opts.scipBin || findScipTs()

  return new Promise((resolve, reject) => {
    if (!fs.existsSync(targetDir)) {
      reject(new Error(`Target directory does not exist: ${targetDir}`))
      return
    }

    const tsconfigPath = opts.tsconfig
      ? path.resolve(targetDir, opts.tsconfig)
      : undefined

    const args = ['index', '--output', outPath, '--target', targetDir]
    if (tsconfigPath && fs.existsSync(tsconfigPath)) {
      args.push('--tsconfig', tsconfigPath)
    }

    const child = execFile(
      scipBin,
      args,
      { cwd: targetDir, timeout, maxBuffer: 10 * 1024 * 1024 },
      (err, stdout, stderr) => {
        if (err) {
          if (err.code === 'ENOENT') {
            reject(new Error(
              `scip-typescript not found. Install it with: npm install -g @sourcegraph/scip-typescript`
            ))
          } else if (err.killed) {
            reject(new Error(
              `scip-typescript timed out after ${timeout / 1000}s indexing ${targetDir}`
            ))
          } else {
            reject(new Error(
              `scip-typescript failed: ${stderr || err.message}`
            ))
          }
          return
        }

        if (!fs.existsSync(outPath)) {
          reject(new Error(
            `scip-typescript completed but produced no output file at ${outPath}`
          ))
          return
        }

        try {
          const buffer = fs.readFileSync(outPath)
          const { symbols, files } = parseScipDocument(buffer)
          const result = {
            files,
            symbolCount: symbols.length,
            symbols,
            outputPath: outPath,
          }

          if (!opts.keepOutput) {
            fs.unlinkSync(outPath)
          }

          resolve(result)
        } catch (readErr) {
          reject(new Error(
            `Failed to read SCIP output: ${readErr.message}`
          ))
        }
      }
    )

    if (opts.onLog && typeof opts.onLog === 'function') {
      child.stdout?.on('data', (d) => opts.onLog('stdout', d.toString()))
      child.stderr?.on('data', (d) => opts.onLog('stderr', d.toString()))
    }
  })
}

module.exports = { indexTypescript, parseScipDocument, findScipTs }
