    41Ôćĺ
    42Ôćĺfunction createSchema(db: Database): void {
    43Ôćĺ  db.exec(`
    44Ôćĺ    CREATE TABLE IF NOT EXISTS documents (
    45Ôćĺ      id    INTEGER PRIMARY KEY AUTOINCREMENT,
    46Ôćĺ      path  TEXT    NOT NULL,
    47Ôćĺ      hash  TEXT
    48Ôćĺ    );
    49Ôćĺ    CREATE TABLE IF NOT EXISTS symbols (
    50Ôćĺ      id            INTEGER PRIMARY KEY AUTOINCREMENT,
    51Ôćĺ      name          TEXT    NOT NULL,
    52Ôćĺ      kind          TEXT    NOT NULL,
    53Ôćĺ      definition    TEXT,
    54Ôćĺ      document_id   INTEGER REFERENCES documents(id) ON DELETE CASCADE
    55Ôćĺ    );
    56Ôćĺ    CREATE INDEX IF NOT EXISTS idx_symbols_name ON symbols(name);
    57Ôćĺ    CREATE INDEX IF NOT EXISTS idx_symbols_document ON symbols(document_id);
    58Ôćĺ  `);
