    68Ôćĺfunction parseScipOutput(scipPath: string): ScipSymbol[] {
    69Ôćĺ  if (!existsSync(scipPath)) return [];
    70Ôćĺ
    71Ôćĺ  const raw = readFileSync(scipPath, "utf-8");
    72Ôćĺ  try {
    73Ôćĺ    const doc = JSON.parse(raw);
