    80Ôćĺ
    81Ôćĺfunction extractSymbols(doc: Record<string, unknown>): ScipSymbol[] {
    82Ôćĺ  const symbols: ScipSymbol[] = [];
    83Ôćĺ  const externalSymbols: Record<string, unknown> =
    84Ôćĺ    (doc.external_symbols as Record<string, unknown>) ?? {};
    85Ôćĺ  const internalSymbols: Record<string, unknown> =
    86Ôćĺ    (doc.internal_symbols as Record<string, unknown>) ?? {};
    87Ôćĺ  const documents: Record<string, unknown> =
    88Ôćĺ    (doc.documents as Record<string, unknown>) ?? {};
