    93Ôćĺ  for (const [docId, docData] of Object.entries(documents)) {
    94Ôćĺ    const relativePath = (docData as Record<string, unknown>).relative_path as
    95Ôćĺ      | string
    96Ôćĺ      | undefined;
    97Ôćĺ    if (relativePath) pathByDocId[docId] = relativePath;
    98Ôćĺ  }
    99Ôćĺ
   100Ôćĺ  for (const [symbolKey, symData] of Object.entries(allSymbols)) {
   101Ôćĺ    const sym = symData as Record<string, unknown>;
   102Ôćĺ    const relationships = sym.relationships as Record<string, unknown> | undefined;
   103Ôćĺ    const defRef = relationships?.definition_reference as
   104Ôćĺ      | Record<string, unknown>
   105Ôćĺ      | undefined;
   106Ôćĺ    const docRef = defRef?.document as string | undefined;
   107Ôćĺ
   108Ôćĺ    symbols.push({
   109Ôćĺ      name: symbolKey,
   110Ôćĺ      kind: (sym.kind as string) ?? "unknown",
   111Ôćĺ      definition: defRef
   112Ôćĺ        ? `${pathByDocId[docRef ?? ""] ?? docRef}:${defRef.start_line ?? 0}`
   113Ôćĺ        : undefined,
   114Ôćĺ      documentPath: docRef ? pathByDocId[docRef] : undefined,
   115Ôćĺ    });
   116Ôćĺ  }
   117Ôćĺ
   118Ôćĺ  return symbols;
   119Ôćĺ}
   120Ôćĺ
   121Ôćĺexport async function buildIndex(
   122Ôćĺ  projectPath: string,
   123Ôćĺ  projectType: ProjectType
   124Ôćĺ): Promise<IndexResult> {
   125Ôćĺ  const spec = indexerCommand(projectType);
   126Ôćĺ  if (!spec) {
   127Ôćĺ    return { success: false, error: `unsupported project type: ${projectType}` };
   128Ôćĺ  }
   129Ôćĺ
   130Ôćĺ  try {
   131Ôćĺ    await execFileAsync(spec.cmd, spec.args, { cwd: projectPath });
   132Ôćĺ  } catch (err) {
   133Ôćĺ    const msg = err instanceof Error ? err.message : String(err);
   134Ôćĺ    return { success: false, error: `indexer failed: ${msg}` };
   135Ôćĺ  }
   136Ôćĺ
   137Ôćĺ  const scipPath = join(projectPath, "index.scip");
   138Ôćĺ  if (!existsSync(scipPath)) {
   139Ôćĺ    return {
   140Ôćĺ      success: false,
   141Ôćĺ      error: `indexer produced no output at ${scipPath}`,
   142Ôćĺ    };
   143Ôćĺ  }
   144Ôćĺ
   145Ôćĺ  const symbols = parseScipOutput(scipPath);
   146Ôćĺ  const dbPath = join(projectPath, `${basename(projectPath)}.fg-index.db`);
   147Ôćĺ
   148Ôćĺ  const db = sqliteOpen(dbPath);
   149Ôćĺ  try {
   150Ôćĺ    createSchema(db);
   151Ôćĺ
   152Ôćĺ    const insertDoc = db.prepare(
   153Ôćĺ      "INSERT INTO documents (path) VALUES (?) ON CONFLICT DO NOTHING"
   154Ôćĺ    );
   155Ôćĺ    const getDocId = db.prepare(
   156Ôćĺ      "SELECT id FROM documents WHERE path = ?"
   157Ôćĺ    );
   158Ôćĺ    const insertSym = db.prepare(
   159Ôćĺ      "INSERT INTO symbols (name, kind, definition, document_id) VALUES (?, ?, ?, ?)"
   160Ôćĺ    );
   161Ôćĺ
   162Ôćĺ    const tx = db.transaction(() => {
   163Ôćĺ      const docPaths = new Set<string>();
   164Ôćĺ      let symCount = 0;
   165Ôćĺ
   166Ôćĺ      for (const sym of symbols) {
   167Ôćĺ        if (sym.documentPath) docPaths.add(sym.documentPath);
   168Ôćĺ      }
   169Ôćĺ
   170Ôćĺ      for (const p of docPaths) {
