   177Ôćĺ              ?.id ?? null
   178Ôćĺ          : null;
   179Ôćĺ        insertSym.run(sym.name, sym.kind, sym.definition ?? null, docId);
   180Ôćĺ        symCount++;
   181Ôćĺ      }
   182Ôćĺ
   183Ôćĺ      return { documentCount: docPaths.size, symbolCount: symCount };
   184Ôćĺ    });
   185Ôćĺ
   186Ôćĺ    const counts = tx();
   187Ôćĺ    db.close();
   188Ôćĺ
   189Ôćĺ    return {
   190Ôćĺ      success: true,
   191Ôćĺ      dbPath,
   192Ôćĺ      documentCount: counts.documentCount,
   193Ôćĺ      symbolCount: counts.symbolCount,
   194Ôćĺ    };
   195Ôćĺ  } catch (err) {
