    42Ôćĺfunction isJavaScriptFile(filePath) {
    43Ôćĺ  return filePath.endsWith('.js') || filePath.endsWith('.ts') || filePath.endsWith('.jsx') || filePath.endsWith('.tsx');
    44Ôćĺ}
