    46Ôćĺfunction extractSymbols(content, filePath) {
    47Ôćĺ  const symbols = [];
    48Ôćĺ
    49Ôćĺ  // Function declarations: function name() or function name() { }
    50Ôćĺ  const funcDeclRegex = /function\s+(\w+)\s*\(/g;
    51Ôćĺ  let match;
    52Ôćĺ  while ((match = funcDeclRegex.exec(content)) !== null) {
    53Ôćĺ    symbols.push({ name: match[1], type: 'function', file: filePath, line: getLineNumber(content, match.index) });
    54Ôćĺ  }
    55Ôćĺ
    56Ôćĺ  // Arrow functions with const: const name = () =>
    57Ôćĺ  const arrowFuncRegex = /const\s+(\w+)\s*=\s*(?:\([^)]*\)|[^=]*)\s*=>/g;
    58Ôćĺ  while ((match = arrowFuncRegex.exec(content)) !== null) {
    59Ôćĺ    symbols.push({ name: match[1], type: 'function', file: filePath, line: getLineNumber(content, match.index) });
    60Ôćĺ  }
    61Ôćĺ
    62Ôćĺ  // Class declarations: class Name
    63Ôćĺ  const classRegex = /class\s+(\w+)(?:\s+extends\s+\w+)?\s*\{/g;
    64Ôćĺ  while ((match = classRegex.exec(content)) !== null) {
    65Ôćĺ    symbols.push({ name: match[1], type: 'class', file: filePath, line: getLineNumber(content, match.index) });
    66Ôćĺ  }
    67Ôćĺ
    68Ôćĺ  // Method definitions: name() { }
    69Ôćĺ  const methodRegex = /(?:^|\s)(\w+)\s*\([^)]*\)\s*\{/gm;
    70Ôćĺ  while ((match = methodRegex.exec(content)) !== null) {
    71Ôćĺ    const prevChar = content[match.index - 1];
    72Ôćĺ    if (prevChar !== '.' && prevChar !== '>' && prevChar !== '=') {
    73Ôćĺ      symbols.push({ name: match[1], type: 'method', file: filePath, line: getLineNumber(content, match.index) });
    74Ôćĺ    }
    75Ôćĺ  }
    76Ôćĺ
    77Ôćĺ  // Variable declarations: const name, let name, var name
    78Ôćĺ  const varRegex = /(?:const|let|var)\s+(\w+)\s*=/g;
    79Ôćĺ  while ((match = varRegex.exec(content)) !== null) {
    80Ôćĺ    symbols.push({ name: match[1], type: 'variable', file: filePath, line: getLineNumber(content, match.index) });
    81Ôćĺ  }
    82Ôćĺ
    83Ôćĺ  // Exports: module.exports = { name } or exports.name
    84Ôćĺ  const exportRegex = /exports\.(\w+)/g;
    85Ôćĺ  while ((match = exportRegex.exec(content)) !== null) {
    86Ôćĺ    symbols.push({ name: match[1], type: 'export', file: filePath, line: getLineNumber(content, match.index) });
    87Ôćĺ  }
    88Ôćĺ
    89Ôćĺ  return symbols;
    90Ôćĺ}
    91Ôćĺ
    92Ôćĺfunction getLineNumber(content, index) {
    93Ôćĺ  const lines = content.substring(0, index).split('\n');
    94Ôćĺ  return lines.length;
    95Ôćĺ}
