    97Ôćĺfunction findReferences(symbolName, content, filePath) {
    98Ôćĺ  const references = [];
    99Ôćĺ  const regex = new RegExp(`\\b${symbolName}\\b`, 'g');
   100Ôćĺ  let match;
   101Ôćĺ
   102Ôćĺ  while ((match = regex.exec(content)) !== null) {
   103Ôćĺ    const line = getLineNumber(content, match.index);
   104Ôćĺ    const lines = content.split('\n');
   105Ôćĺ    const lineContent = lines[line - 1]?.trim() || '';
   106Ôćĺ    references.push({ file: filePath, line, content: lineContent });
   107Ôćĺ  }
   108Ôćĺ
   109Ôćĺ  return references;
   110Ôćĺ}
