   112Ôćĺfunction indexDirectory(dirPath) {
   113Ôćĺ  const db = loadDatabase();
   114Ôćĺ  const files = [];
   115Ôćĺ
   116Ôćĺ  function walkDir(currentPath) {
   117Ôćĺ    const entries = fs.readdirSync(currentPath, { withFileTypes: true });
   118Ôćĺ    for (const entry of entries) {
   119Ôćĺ      const fullPath = path.join(currentPath, entry.name);
   120Ôćĺ      if (entry.isDirectory()) {
   121Ôćĺ        if (entry.name !== 'node_modules' && entry.name !== '.git' && !entry.name.startsWith('.')) {
   122Ôćĺ          walkDir(fullPath);
   123Ôćĺ        }
   124Ôćĺ      } else if (isJavaScriptFile(fullPath)) {
   125Ôćĺ        files.push(fullPath);
   126Ôćĺ      }
   127Ôćĺ    }
   128Ôćĺ  }
   129Ôćĺ
   130Ôćĺ  try {
   131Ôćĺ    walkDir(dirPath);
   132Ôćĺ  } catch (e) {
   133Ôćĺ    console.error(`Error reading directory: ${e.message}`);
   134Ôćĺ    process.exit(EXIT_ERROR);
   135Ôćĺ  }
   136Ôćĺ
   137Ôćĺ  let totalSymbols = 0;
   138Ôćĺ
   139Ôćĺ  for (const file of files) {
   140Ôćĺ    try {
   141Ôćĺ      const content = fs.readFileSync(file, 'utf8');
   142Ôćĺ      const symbols = extractSymbols(content, file);
   143Ôćĺ      const relativePath = path.relative(process.cwd(), file);
   144Ôćĺ
   145Ôćĺ      db.files[relativePath] = {
   146Ôćĺ        path: relativePath,
   147Ôćĺ        symbols: symbols.map(s => s.name),
   148Ôćĺ        indexedAt: new Date().toISOString()
   149Ôćĺ      };
   150Ôćĺ
   151Ôćĺ      for (const symbol of symbols) {
   152Ôćĺ        if (!db.symbols[symbol.name]) {
   153Ôćĺ          db.symbols[symbol.name] = [];
   154Ôćĺ        }
   155Ôćĺ        db.symbols[symbol.name].push({
   156Ôćĺ          type: symbol.type,
   157Ôćĺ          file: relativePath,
   158Ôćĺ          line: symbol.line
   159Ôćĺ        });
   160Ôćĺ        totalSymbols++;
   161Ôćĺ      }
   162Ôćĺ
   163Ôćĺ      // Build relationships (which symbols reference which)
   164Ôćĺ      for (const symbol of symbols) {
