{"role":"user","content":[{"tool_use_id":"call_1b3d1ea95bfe4d10b49af943","type":"tool_result","content":"     1Ôćĺimport { execFile } from "node:child_process";
     2Ôćĺimport { readFile, unlink, access, constants } from "node:fs/promises";
     3Ôćĺimport { promisify } from "node:util";
     4Ôćĺ
     5Ôćĺconst execFileAsync = promisify(execFile);
     6Ôćĺ
     7Ôćĺexport interface IndexResult {
     8Ôćĺ  files: string[];
     9Ôćĺ  symbolCount: number;
    10Ôćĺ  scipOutputPath: string;
    11Ôćĺ}
    12Ôćĺ
    13Ôćĺexport interface IndexOptions {
    14Ôćĺ  projectRoot: string;
    15Ôćĺ  output?: string;
    16Ôćĺ  projectName?: string;
    17Ôćĺ  inferTsconfig?: boolean;
    18Ôćĺ  yarnWorkspaces?: boolean;
    19Ôćĺ  pnpmWorkspaces?: boolean;
