    29Ôćĺexport type ParserFn = (input: ParserInput) => Promise<{ files: string[]; symbolCount: number }>;
    30Ôćĺ
    31Ôćĺclass TypescriptIndexerError extends Error {
    32Ôćĺ  constructor(
    33Ôćĺ    message: string,
    34Ôćĺ    public readonly cause?: Error,
    35Ôćĺ    public readonly exitCode?: number,
    36Ôćĺ  ) {
    37Ôćĺ    super(message);
    38Ôćĺ    this.name = "TypescriptIndexerError";
    39Ôćĺ  }
    40Ôćĺ}
    41Ôćĺ
    42Ôćĺfunction resolveOutputPath(projectRoot: string, output?: string): string {
    43Ôćĺ  if (output) {
    44Ôćĺ    return output.startsWith("/") ? output : `${projectRoot}/${output}`;
    45Ôćĺ  }
    46Ôćĺ  return `${projectRoot}/dump.scip`;
    47Ôćĺ}
    48Ôćĺ
    49Ôćĺasync function assertDirectory(dir: string): Promise<void> {
    50Ôćĺ  try {
    51Ôćĺ    await access(dir, constants.R_OK | constants.X_OK);
    52Ôćĺ  } catch {
    53Ôćĺ    throw new TypescriptIndexerError(`Directory does not exist or is not readable: ${dir}`);
    54Ôćĺ  }
    55Ôćĺ}
    56Ôćĺ
    57Ôćĺasync function runScipTypescript(options: IndexOptions): Promise<string> {
    58Ôćĺ  const args = ["index"];
    59Ôćĺ
    60Ôćĺ  if (options.projectName) {
    61Ôćĺ    args.push(`--project_name=${options.projectName}`);
    62Ôćĺ  }
    63Ôćĺ
    64Ôćĺ  const outputPath = resolveOutputPath(options.projectRoot, options.output);
    65Ôćĺ  args.push(`--output=${outputPath}`);
    66Ôćĺ
    67Ôćĺ  if (options.inferTsconfig) args.push("--infer-tsconfig");
    68Ôćĺ  if (options.yarnWorkspaces) args.push("--yarn-workspaces");
    69Ôćĺ  if (options.pnpmWorkspaces) args.push("--pnpm-workspaces");
    70Ôćĺ  if (options.noGlobalCaches) args.push("--no-global-caches");
    71Ôćĺ  if (options.progressBar) args.push("--progress-bar");
    72Ôćĺ
    73Ôćĺ  let result;
    74Ôćĺ  try {
    75Ôćĺ    result = await execFileAsync("scip-typescript", args, {
    76Ôćĺ      cwd: options.projectRoot,
    77Ôćĺ      maxBuffer: 50 * 1024 * 1024,
    78Ôćĺ      timeout: 600_000,
    79Ôćĺ    });
    80Ôćĺ  } catch (err: unknown) {
    81Ôćĺ    const e = err as { stderr?: string; code?: number; message?: string };
    82Ôćĺ    if (e.code === "ENOENT") {
    83Ôćĺ      throw new TypescriptIndexerError(
    84Ôćĺ        "scip-typescript not found. Install it globally: npm install -g @sourcegraph/scip-typescript",
    85Ôćĺ      );
    86Ôćĺ    }
    87Ôćĺ    const stderr = e.stderr || "";
    88Ôćĺ    if (stderr.includes("heap out of memory") || stderr.includes("FATAL ERROR")) {
    89Ôćĺ      throw new TypescriptIndexerError(
    90Ôćĺ        "scip-typescript ran out of memory. " +
    91Ôćĺ          "Try running with --no-global-caches or increase Node memory with " +
    92Ôćĺ          "NODE_OPTIONS='--max-old-space-size=16000'",
    93Ôćĺ        undefined,
    94Ôćĺ        e.code,
    95Ôćĺ      );
    96Ôćĺ    }
    97Ôćĺ    if (stderr.includes("Cannot find module") || stderr.includes("Cannot read file")) {
    98Ôćĺ      throw new TypescriptIndexerError(
    99Ôćĺ        `Project dependencies may not be installed. Run 'npm install' in ${options.projectRoot}`,
   100Ôćĺ        undefined,
   101Ôćĺ        e.code,
   102Ôćĺ      );
   103Ôćĺ    }
   104Ôćĺ    throw new TypescriptIndexerError(
   105Ôćĺ      `scip-typescript failed (exit code ${e.code ?? "unknown"}): ${stderr || e.message}`,
   106Ôćĺ      undefined,
   107Ôćĺ      e.code,
   108Ôćĺ    );
   109Ôćĺ  }
   110Ôćĺ
   111Ôćĺ  if (result.stderr) {
   112Ôćĺ    const warnings = result.stderr
   113Ôćĺ      .split("\n")
   114Ôćĺ      .filter((line) => line.trim().length > 0)
   115Ôćĺ      .slice(0, 5);
   116Ôćĺ    console.warn("[typescript-indexer] warnings from scip-typescript:");
   117Ôćĺ    for (const w of warnings) {
   118Ôćĺ      console.warn(`  ${w}`);
   119Ôćĺ    }
   120Ôćĺ  }
   121Ôćĺ
   122Ôćĺ  return outputPath;
   123Ôćĺ}
   124Ôćĺ
   125Ôćĺfunction extractScipMetadata(scipBuffer: Uint8Array): { files: string[]; symbolCount: number } {
   126Ôćĺ  const text = new TextDecoder("utf-8", { fatal: false }).decode(scipBuffer);
   127Ôćĺ  const files = new Set<string>();
   128Ôćĺ  let symbolCount = 0;
   129Ôćĺ
   130Ôćĺ  const pathRegex = new RegExp('[\x00-\x1F]*file://([^\x00]*)', "g");
   131Ôćĺ  let match;
   132Ôćĺ  while ((match = pathRegex.exec(text)) !== null) {
   133Ôćĺ    files.add(match[1]);
   134Ôćĺ  }
   135Ôćĺ
   136Ôćĺ  symbolCount = (text.match(/\x1aSymbol/g) || []).length;
   137Ôćĺ  return { files: Array.from(files), symbolCount };
   138Ôćĺ}
