   140Ôćĺexport async function indexTypescript(
   141Ôćĺ  options: IndexOptions,
   142Ôćĺ  parser?: ParserFn,
   143Ôćĺ): Promise<IndexResult> {
   144Ôćĺ  await assertDirectory(options.projectRoot);
