   146Ôćĺ  const scipOutputPath = await runScipTypescript(options);
   147Ôćĺ
   148Ôćĺ  let files: string[];
   149Ôćĺ  let symbolCount: number;
   150Ôćĺ
   151Ôćĺ  if (parser) {
   152Ôćĺ    const parsed = await parser({ scipOutputPath, projectRoot: options.projectRoot });
   153Ôćĺ    files = parsed.files;
   154Ôćĺ    symbolCount = parsed.symbolCount;
   155Ôćĺ  } else {
   156Ôćĺ    let scipBuffer: Uint8Array;
   157Ôćĺ    try {
   158Ôćĺ      scipBuffer = new Uint8Array(await readFile(scipOutputPath));
   159Ôćĺ    } catch {
   160Ôćĺ      throw new TypescriptIndexerError(
   161Ôćĺ        `SCIP output file not found or unreadable: ${scipOutputPath}. ` +
   162Ôćĺ          "scip-typescript may have failed silently.",
   163Ôćĺ      );
   164Ôćĺ    }
   165Ôćĺ
   166Ôćĺ    if (scipBuffer.length === 0) {
   167Ôćĺ      throw new TypescriptIndexerError(
   168Ôćĺ        `SCIP output file is empty: ${scipOutputPath}. ` +
   169Ôćĺ          "The target directory may contain no TypeScript files.",
   170Ôćĺ      );
