   173Ôćĺ    const result = extractScipMetadata(scipBuffer);
   174Ôćĺ    files = result.files;
   175Ôćĺ    symbolCount = result.symbolCount;
   176Ôćĺ  }
   177Ôćĺ
   178Ôćĺ  return {
   179Ôćĺ    files,
   180Ôćĺ    symbolCount,
   181Ôćĺ    scipOutputPath,
   182Ôćĺ  };
   183Ôćĺ}
   184Ôćĺ
