    31Ôćĺexport function parseScipSymbols(doc: ParsedScipDocument): ScipSymbol[] {
    32Ôćĺ  const seen = new Set<string>();
    33Ôćĺ  const symbols: ScipSymbol[] = [];
    34Ôćĺ  for (const occ of doc.occurrences) {
    35Ôćĺ    if (seen.has(occ.symbol)) continue;
    36Ôćĺ    seen.add(occ.symbol);
    37Ôćĺ    const parts = occ.symbol.split(" ");
    38Ôćĺ    symbols.push({
    39Ôćĺ      scheme: parts[0] || "",
    40Ôćĺ      entity: parts[1] || "",
    41Ôćĺ      descriptor: parts.slice(2).join(" "),
    42Ôćĺ    });
    43Ôćĺ  }
    44Ôćĺ  return symbols;
    45Ôćĺ}
    46Ôćĺ
    47Ôćĺinterface ScipIndex {
    48Ôćĺ  metadata: {
    49Ôćĺ    toolInfo: { name: string; version: string };
    50Ôćĺ    projectRoot: string;
    51Ôćĺ    textDocumentEncoding: string;
