    62Ôćĺ  const errors: string[] = [];
    63Ôćĺ
    64Ôćĺ  if (!data.documents) {
    65Ôćĺ    errors.push("SCIP output contains no documents");
    66Ôćĺ    return { files, symbolCount, errors };
    67Ôćĺ  }
    68Ôćĺ
    69Ôćĺ  for (const [relPath, doc] of Object.entries(data.documents)) {
    70Ôćĺ    if (!relPath || !doc) {
    71Ôćĺ      errors.push(`Skipping invalid document entry`);
    72Ôćĺ      continue;
