    74Ôćĺ    files.push(relPath);
    75Ôćĺ    const symbols = parseScipSymbols(doc as ParsedScipDocument);
    76Ôćĺ    symbolCount += symbols.length;
    77Ôćĺ  }
    78Ôćĺ
    79Ôćĺ  return { files, symbolCount, errors };
