import { execFile } from "node:child_process";
import { readFile, unlink, access, constants } from "node:fs/promises";
import { promisify } from "node:util";

const execFileAsync = promisify(execFile);

export interface IndexResult {
  files: string[];
  symbolCount: number;
  scipOutputPath: string;
}

export interface IndexOptions {
  projectRoot: string;
  output?: string;
  projectName?: string;
  inferTsconfig?: boolean;
  yarnWorkspaces?: boolean;
  pnpmWorkspaces?: boolean;
  noGlobalCaches?: boolean;
  progressBar?: boolean;
}

export interface ParserInput {
  scipOutputPath: string;
  projectRoot: string;
}

export type ParserFn = (input: ParserInput) => Promise<{ files: string[]; symbolCount: number }>;

class TypescriptIndexerError extends Error {
  constructor(
    message: string,
    public readonly cause?: Error,
    public readonly exitCode?: number,
  ) {
    super(message);
    this.name = "TypescriptIndexerError";
  }
}

function resolveOutputPath(projectRoot: string, output?: string): string {
  if (output) {
    return output.startsWith("/") ? output : `${projectRoot}/${output}`;
  }
  return `${projectRoot}/dump.scip`;
}

async function assertDirectory(dir: string): Promise<void> {
  try {
    await access(dir, constants.R_OK | constants.X_OK);
  } catch {
    throw new TypescriptIndexerError(`Directory does not exist or is not readable: ${dir}`);
  }
}

async function runScipTypescript(options: IndexOptions): Promise<string> {
  const args = ["index"];

  if (options.projectName) {
    args.push(`--project_name=${options.projectName}`);
  }

  const outputPath = resolveOutputPath(options.projectRoot, options.output);
  args.push(`--output=${outputPath}`);

  if (options.inferTsconfig) args.push("--infer-tsconfig");
  if (options.yarnWorkspaces) args.push("--yarn-workspaces");
  if (options.pnpmWorkspaces) args.push("--pnpm-workspaces");
  if (options.noGlobalCaches) args.push("--no-global-caches");
  if (options.progressBar) args.push("--progress-bar");

  let result;
  try {
    result = await execFileAsync("scip-typescript", args, {
      cwd: options.projectRoot,
      maxBuffer: 50 * 1024 * 1024,
      timeout: 600_000,
    });
  } catch (err: unknown) {
    const e = err as { stderr?: string; code?: number; message?: string };
    if (e.code === "ENOENT") {
      throw new TypescriptIndexerError(
        "scip-typescript not found. Install it globally: npm install -g @sourcegraph/scip-typescript",
      );
    }
    const stderr = e.stderr || "";
    if (stderr.includes("heap out of memory") || stderr.includes("FATAL ERROR")) {
      throw new TypescriptIndexerError(
        "scip-typescript ran out of memory. " +
          "Try running with --no-global-caches or increase Node memory with " +
          "NODE_OPTIONS='--max-old-space-size=16000'",
        undefined,
        e.code,
      );
    }
    if (stderr.includes("Cannot find module") || stderr.includes("Cannot read file")) {
      throw new TypescriptIndexerError(
        `Project dependencies may not be installed. Run 'npm install' in ${options.projectRoot}`,
        undefined,
        e.code,
      );
    }
    throw new TypescriptIndexerError(
      `scip-typescript failed (exit code ${e.code ?? "unknown"}): ${stderr || e.message}`,
      undefined,
      e.code,
    );
  }

  if (result.stderr) {
    const warnings = result.stderr
      .split("\n")
      .filter((line) => line.trim().length > 0)
      .slice(0, 5);
    console.warn("[typescript-indexer] warnings from scip-typescript:");
    for (const w of warnings) {
      console.warn(`  ${w}`);
    }
  }

  return outputPath;
}

function extractScipMetadata(scipBuffer: Uint8Array): { files: string[]; symbolCount: number } {
  const text = new TextDecoder("utf-8", { fatal: false }).decode(scipBuffer);
  const files = new Set<string>();
  let symbolCount = 0;

  const pathRegex = new RegExp('[\x00-\x1F]*file://([^\x00]*)', "g");
  let match;
  while ((match = pathRegex.exec(text)) !== null) {
    files.add(match[1]);
  }

  symbolCount = (text.match(/\x1aSymbol/g) || []).length;
  return { files: Array.from(files), symbolCount };
}

export async function indexTypescript(
  options: IndexOptions,
  parser?: ParserFn,
): Promise<IndexResult> {
  await assertDirectory(options.projectRoot);

  const scipOutputPath = await runScipTypescript(options);

  let files: string[];
  let symbolCount: number;

  if (parser) {
    const parsed = await parser({ scipOutputPath, projectRoot: options.projectRoot });
    files = parsed.files;
    symbolCount = parsed.symbolCount;
  } else {
    let scipBuffer: Uint8Array;
    try {
      scipBuffer = new Uint8Array(await readFile(scipOutputPath));
    } catch {
      throw new TypescriptIndexerError(
        `SCIP output file not found or unreadable: ${scipOutputPath}. ` +
          "scip-typescript may have failed silently.",
      );
    }

    if (scipBuffer.length === 0) {
      throw new TypescriptIndexerError(
        `SCIP output file is empty: ${scipOutputPath}. ` +
          "The target directory may contain no TypeScript files.",
      );
    }

    const result = extractScipMetadata(scipBuffer);
    files = result.files;
    symbolCount = result.symbolCount;
  }

  return {
    files,
    symbolCount,
    scipOutputPath,
  };
}

export async function cleanupScipOutput(scipOutputPath: string): Promise<void> {
  try {
    await unlink(scipOutputPath);
  } catch {
    // already removed or never created ÔÇö safe to ignore
  }
}
