 * SCIP Indexer
 * Main module that orchestrates parsing SCIP index files and populating the symbol database
 */

const fs = require('fs');
const path = require('path');
const { loadScipIndex } = require('./scip-parser');
const { SymbolDatabase } = require('./symbol-database');
const { generateSymbolId, parseSymbol, SYMBOL_KIND_MAP } = require('./scip-utils');

/**
 * Extract location from SCIP range
 * SCIP ranges can be 3 or 4 integers:
 * - 3 integers: [startLine, startCharacter, endCharacter] (single line)
 * - 4 integers: [startLine, startCharacter, endLine, endCharacter] (multi-line)
 * @param {number[]} range - SCIP range array
 * @param {string} filePath - File path
 * @returns {Object} Location object
 */
function extractLocation(range, filePath) {
  if (!range || range.length < 3) {
    return null;
  }

  if (range.length === 3) {
    // Single line range: [line, startChar, endChar]
    return {
      file: filePath,
      line: range[0],
      column: range[1],
      endLine: range[0],
      endColumn: range[2],
    };
  } else {
    // Multi-line range: [startLine, startChar, endLine, endChar]
    return {
      file: filePath,
      line: range[0],
      column: range[1],
      endLine: range[2],
      endColumn: range[3],
    };
  }
}

/**
 * Extract symbol name from SCIP descriptor
 * @param {string} descriptor - SCIP descriptor part
 * @returns {string} Symbol name
 */
function extractSymbolName(descriptor) {
  if (!descriptor) return '';

  // SCIP descriptors use various separators
  // Common patterns: package/module/class.method, namespace/class#method, etc.
  const parts = descriptor.split(/[./#:]/);
  return parts[parts.length - 1] || descriptor;
}

