function processScipIndex(scipIndex, database) {
  const stats = {
    documentsProcessed: 0,
    symbolsExtracted: 0,
    definitionsFound: 0,
    referencesFound: 0,
    relationshipsFound: 0,
    externalSymbols: 0,
