async function indexScipFile(scipFilePath, database = null) {
  if (!fs.existsSync(scipFilePath)) {
    throw new Error(`SCIP file not found: ${scipFilePath}`);
  }

  const db = database || new SymbolDatabase();
  const scipIndex = loadScipIndex(scipFilePath);
  const stats = processScipIndex(scipIndex, db);

  return { database: db, stats };
}

