 * Index multiple SCIP files
 * @param {string[]} scipFilePaths - Array of SCIP file paths
 * @returns {Promise<{database: SymbolDatabase, stats: Object}>}
 */
async function indexMultipleScipFiles(scipFilePaths) {
  const database = new SymbolDatabase();
  const combinedStats = {
    filesProcessed: 0,
    documentsProcessed: 0,
    symbolsExtracted: 0,
    definitionsFound: 0,
    referencesFound: 0,
    relationshipsFound: 0,
    externalSymbols: 0,
  };

  for (const filePath of scipFilePaths) {
    if (!fs.existsSync(filePath)) {
      console.warn(`Skipping non-existent file: ${filePath}`);
      continue;
    }

    const { stats } = await indexScipFile(filePath, database);
    combinedStats.filesProcessed++;
    combinedStats.documentsProcessed += stats.documentsProcessed;
    combinedStats.symbolsExtracted += stats.symbolsExtracted;
    combinedStats.definitionsFound += stats.definitionsFound;
    combinedStats.referencesFound += stats.referencesFound;
    combinedStats.relationshipsFound += stats.relationshipsFound;
    combinedStats.externalSymbols += stats.externalSymbols;
  }

  return { database, stats: combinedStats };
}

module.exports = {
