/**
 * SCIP Index Parser
 * Parses SCIP (SCIP Code Intelligence Protocol) protobuf output
 * and populates the symbol database.
 */

const fs = require('fs');
const path = require('path');

// SCIP Symbol kinds mapped to internal kinds
const SYMBOL_KIND_MAP = {
  1: 'module',        // UnspecifiedKind
  2: 'module',        // Module
  3: 'namespace',     // Namespace
  4: 'package',       // Package
  5: 'class',         // Class
  6: 'method',        // Method
  7: 'property',      // Property
  8: 'field',         // Field
  9: 'constructor',   // Constructor
  10: 'enum',         // Enum
  11: 'interface',    // Interface
  12: 'function',     // Function
  13: 'variable',     // Variable
  14: 'constant',     // Constant
  15: 'string',       // String (for string literal symbols)
  16: 'number',       // Number
  17: 'boolean',      // Boolean
  18: 'array',        // Array
  19: 'object',       // Object
  20: 'key',          // Key
  21: 'null',         // Null
  22: 'enumMember',   // EnumMember
  23: 'struct',       // Struct
  24: 'event',        // Event
  25: 'operator',     // Operator
  26: 'typeParameter',// TypeParameter
  27: 'parameter',    // Parameter
  28: 'macro',        // Macro
  29: 'typeAlias',    // TypeAlias
  30: 'union',        // Union
};

// SCIP Relationship types
const RELATIONSHIP_TYPE_MAP = {
  0: 'unspecified',
  1: 'implements',
  2: 'extends',
  3: 'references',
};

/**
 * Parse a SCIP symbol string into its components
 * Format: scheme package manager name version descriptor
 * @param {string} symbol - SCIP symbol string
 * @returns {Object} Parsed symbol components
 */
function parseSymbol(symbol) {
  if (!symbol || symbol === '') {
    return null;
  }

  // SCIP symbols use the format: scheme package manager name version descriptor
  // Example: scip-typescript npm typescript 4.9.5 src/lib/index.ts/
  const parts = symbol.split(' ');

  if (parts.length < 4) {
    // Local symbol format or invalid
    return {
      scheme: parts[0] || 'local',
      packageManager: parts[1] || '',
      packageName: parts[2] || '',
      version: parts[3] || '',
      descriptor: parts.slice(4).join(' ') || '',
      isLocal: parts.length < 4,
      raw: symbol,
    };
  }

  return {
    scheme: parts[0],
    packageManager: parts[1],
    packageName: parts[2],
    version: parts[3],
    descriptor: parts.slice(4).join(' '),
    isLocal: false,
    raw: symbol,
  };
}

/**
 * Generate an internal symbol ID from SCIP symbol descriptor
 * @param {string} symbol - SCIP symbol string
 * @returns {string} Internal symbol ID
 */
function generateSymbolId(symbol) {
  const parsed = parseSymbol(symbol);
  if (!parsed) return null;

  // Create a hash-based ID for local symbols
  if (parsed.isLocal) {
    return `local:${hashString(symbol)}`;
  }

  // For package symbols, use a structured ID
  const descriptorHash = hashString(parsed.descriptor);
  return `${parsed.scheme}:${parsed.packageManager}:${parsed.packageName}:${descriptorHash}`;
}

/**
 * Simple string hash function
 * @param {string} str - Input string
 * @returns {string} Hash string
 */
function hashString(str) {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return Math.abs(hash).toString(36);
}

module.exports = {
  SYMBOL_KIND_MAP,
  RELATIONSHIP_TYPE_MAP,
  parseSymbol,
  generateSymbolId,
  hashString,
};
