const { execFile } = require('child_process')
const fs = require('fs')
const path = require('path')

const DEFAULT_TIMEOUT_MS = 120_000

class GoIndexerError extends Error {
  constructor(message, cause) {
    super(message)
    this.name = 'GoIndexerError'
    this.cause = cause || null
  }
}

class ProtobufReader {
  constructor(buffer) {
    this.buffer = buffer
    this.offset = 0
  }

  isEnd() { return this.offset >= this.buffer.length }

  readVarint() {
    let result = 0
    let shift = 0
    let byte
    do {
      if (this.offset >= this.buffer.length) {
        throw new Error('Unexpected end of buffer while reading varint')
      }
      byte = this.buffer[this.offset++]
      result |= (byte & 0x7f) << shift
      shift += 7
    } while (byte & 0x80)
    return result
  }

  readTag() {
    if (this.isEnd()) return null
    const tag = this.readVarint()
    return { field: tag >> 3, wireType: tag & 0x07 }
  }

  readLengthDelimited() {
    const length = this.readVarint()
    if (this.offset + length > this.buffer.length) {
      throw new Error(`Length delimited field exceeds buffer: ${length}`)
    }
    const result = this.buffer.slice(this.offset, this.offset + length)
    this.offset += length
    return result
  }

  skipField(wireType) {
    switch (wireType) {
      case 0: this.readVarint(); break
      case 1: this.offset += 8; break
      case 2: this.readLengthDelimited(); break
      case 5: this.offset += 4; break
      default: throw new Error(`Unknown wire type: ${wireType}`)
    }
  }
}

function parseScipIndex(buffer) {
  const reader = new ProtobufReader(buffer)
  const index = { metadata: null, documents: [], externalSymbols: [] }

  while (!reader.isEnd()) {
    const tag = reader.readTag()
    if (!tag) break
    switch (tag.field) {
      case 1: index.metadata = parseMetadata(reader.readLengthDelimited()); break
      case 2: index.documents.push(parseDocument(reader.readLengthDelimited())); break
      case 3: index.externalSymbols.push(parseSymbolInfo(reader.readLengthDelimited())); break
      default: reader.skipField(tag.wireType)
    }
  }
  return index
}

function parseMetadata(buffer) {
  const reader = new ProtobufReader(buffer)
  const metadata = { version: '', toolInfo: null, projectRoot: '', textDocumentEncoding: 0 }
  while (!reader.isEnd()) {
    const tag = reader.readTag()
    if (!tag) break
    switch (tag.field) {
      case 1: metadata.version = reader.readLengthDelimited().toString('utf8'); break
      case 2: metadata.toolInfo = parseToolInfo(reader.readLengthDelimited()); break
      case 3: metadata.projectRoot = reader.readLengthDelimited().toString('utf8'); break
      case 4: metadata.textDocumentEncoding = reader.readVarint(); break
      default: reader.skipField(tag.wireType)
    }
  }
  return metadata
}

function parseToolInfo(buffer) {
  const reader = new ProtobufReader(buffer)
  const info = { name: '', version: '', arguments: [] }
  while (!reader.isEnd()) {
    const tag = reader.readTag()
    if (!tag) break
    switch (tag.field) {
      case 1: info.name = reader.readLengthDelimited().toString('utf8'); break
      case 2: info.version = reader.readLengthDelimited().toString('utf8'); break
      case 3: info.arguments.push(reader.readLengthDelimited().toString('utf8')); break
      default: reader.skipField(tag.wireType)
    }
  }
  return info
}

function parseDocument(buffer) {
  const reader = new ProtobufReader(buffer)
  const doc = { language: '', relativePath: '', occurrences: [], symbols: [], text: '' }
  while (!reader.isEnd()) {
    const tag = reader.readTag()
    if (!tag) break
    switch (tag.field) {
      case 1: doc.language = reader.readLengthDelimited().toString('utf8'); break
      case 2: doc.relativePath = reader.readLengthDelimited().toString('utf8'); break
      case 3: doc.occurrences.push(parseOccurrence(reader.readLengthDelimited())); break
      case 4: doc.symbols.push(parseSymbolInfo(reader.readLengthDelimited())); break
      case 5: doc.text = reader.readLengthDelimited().toString('utf8'); break
      default: reader.skipField(tag.wireType)
    }
  }
  return doc
}

function parseOccurrence(buffer) {
  const reader = new ProtobufReader(buffer)
  const occ = { range: [], symbol: '', symbolRoles: 0, diagnostics: [] }
  while (!reader.isEnd()) {
    const tag = reader.readTag()
    if (!tag) break
    switch (tag.field) {
      case 1: {
        const rangeBytes = reader.readLengthDelimited()
        const rangeReader = new ProtobufReader(rangeBytes)
        while (!rangeReader.isEnd()) occ.range.push(rangeReader.readVarint())
        break
      }
      case 2: occ.symbol = reader.readLengthDelimited().toString('utf8'); break
      case 3: occ.symbolRoles = reader.readVarint(); break
      default: reader.skipField(tag.wireType)
    }
  }
  return occ
}

function parseSymbolInfo(buffer) {
  const reader = new ProtobufReader(buffer)
  const sym = { symbol: '', kind: 0, displayName: '', documentation: [], relationships: [] }
  while (!reader.isEnd()) {
    const tag = reader.readTag()
    if (!tag) break
    switch (tag.field) {
      case 1: sym.symbol = reader.readLengthDelimited().toString('utf8'); break
      case 2: sym.documentation.push(reader.readLengthDelimited().toString('utf8')); break
      case 4: sym.kind = reader.readVarint(); break
      case 5: sym.displayName = reader.readLengthDelimited().toString('utf8'); break
      case 7: sym.enclosingSymbol = reader.readLengthDelimited().toString('utf8'); break
      default: reader.skipField(tag.wireType)
    }
  }
  return sym
}

function validateTargetDir(targetDir) {
  const absPath = path.resolve(targetDir)

  if (!fs.existsSync(absPath)) {
    throw new GoIndexerError(`Target directory does not exist: ${absPath}`)
  }

  if (!fs.statSync(absPath).isDirectory()) {
    throw new GoIndexerError(`Target path is not a directory: ${absPath}`)
  }

  const goModPath = path.join(absPath, 'go.mod')
  if (!fs.existsSync(goModPath)) {
    throw new GoIndexerError(
      `No go.mod found in ${absPath}. The target directory must be a valid Go module.`
    )
  }

  return absPath
}

async function findScipGo(customPath) {
  if (customPath) {
    if (fs.existsSync(customPath) && fs.statSync(customPath).isFile()) {
      return customPath
    }
    throw new GoIndexerError(`Custom scip-go path does not exist or is not a file: ${customPath}`)
  }

  return new Promise((resolve, reject) => {
    execFile('which', ['scip-go'], (err, stdout) => {
      if (err || !stdout.trim()) {
        reject(new GoIndexerError(
          'scip-go not found in PATH. Install it from https://github.com/sourcegraph/scip-go'
        ))
        return
      }
      resolve(stdout.trim())
    })
  })
}

function runScipGo(scipGoBin, absTargetDir, options = {}) {
  const args = ['index']
  if (options.output) args.push('--output', options.output)

  const timeoutMs = options.timeoutMs || DEFAULT_TIMEOUT_MS

  return new Promise((resolve, reject) => {
    execFile(scipGoBin, args, {
      cwd: absTargetDir,
      maxBuffer: 10 * 1024 * 1024,
      timeout: timeoutMs,
    }, (err, stdout, stderr) => {
      if (err) {
        if (err.code === 'ENOENT') {
          reject(new GoIndexerError(
            'scip-go binary not found. Install it from https://github.com/sourcegraph/scip-go', err
          ))
          return
        }
        if (err.killed && err.signal === 'SIGTERM') {
          reject(new GoIndexerError(
            `scip-go timed out after ${timeoutMs}ms. Try increasing timeoutMs or indexing a smaller project.`, err
          ))
          return
        }
        const stderrStr = (stderr || '').trim()
        if (stderrStr.includes('fatal error') || stderrStr.includes('FATAL')) {
          reject(new GoIndexerError(`scip-go crashed: ${stderrStr}`, err))
          return
        }
        if (stderrStr.includes('go:')) {
          reject(new GoIndexerError(
            `Go toolchain error: ${stderrStr}. Ensure Go dependencies are installed (run "go mod download").`, err
          ))
          return
        }
        reject(new GoIndexerError(
          `scip-go failed (exit code ${err.code || 'unknown'}): ${stderrStr || err.message}`, err
        ))
        return
      }

      if (stderr) {
        const warnings = stderr.split('\n').filter(l => l.trim().length > 0).slice(0, 5)
        if (warnings.length > 0) {
          console.warn('[go-indexer] warnings from scip-go:')
          for (const w of warnings) console.warn(`  ${w}`)
        }
      }
      resolve()
    })
  })
}

function resolveScipOutputPath(absTargetDir, outputOption) {
  if (outputOption) {
    return path.isAbsolute(outputOption) ? outputOption : path.join(absTargetDir, outputOption)
  }
  return path.join(absTargetDir, 'index.scip')
}

function parseScipResult(scipOutputPath, absTargetDir) {
  if (!fs.existsSync(scipOutputPath)) {
    throw new GoIndexerError(
      `scip-go completed but no output file found at ${scipOutputPath}. ` +
      'The target directory may contain no Go files.'
    )
  }

  const fileStat = fs.statSync(scipOutputPath)
  if (fileStat.size === 0) {
    throw new GoIndexerError(
      `SCIP output file is empty: ${scipOutputPath}. scip-go may have failed silently.`
    )
  }

  let scipIndex
  try {
    const buffer = fs.readFileSync(scipOutputPath)
    scipIndex = parseScipIndex(buffer)
  } catch (err) {
    throw new GoIndexerError(
      `Failed to parse SCIP output at ${scipOutputPath}: ${err.message}`, err
    )
  }

  const files = []
  let symbolCount = 0

  for (const doc of scipIndex.documents || []) {
    if (doc.relativePath) {
      files.push(path.resolve(absTargetDir, doc.relativePath))
    }
    const docSymbols = new Set()
    for (const occ of doc.occurrences || []) {
      if (occ.symbol && !docSymbols.has(occ.symbol)) {
        docSymbols.add(occ.symbol)
        symbolCount++
      }
    }
    for (const sym of doc.symbols || []) {
      if (sym.symbol && !docSymbols.has(sym.symbol)) {
        docSymbols.add(sym.symbol)
        symbolCount++
      }
    }
  }

  for (const extSym of scipIndex.externalSymbols || []) {
    symbolCount++
  }

  return { files, symbolCount }
}

/**
 * Index a Go project by running scip-go and feeding output to the SCIP parser.
 *
 * @param {string} targetDir - Path to the Go project root (must contain go.mod)
 * @param {Object} [options] - Configuration options
 * @param {string} [options.scipGoPath] - Custom path to scip-go binary
 * @param {string} [options.output] - Custom output path for index.scip
 * @param {number} [options.timeoutMs] - Execution timeout in milliseconds (default: 120000)
 * @param {boolean} [options.keepOutput] - If true, don't clean up the SCIP output file
 * @returns {Promise<{files: string[], symbolCount: number, scipOutputPath: string}>}
 */
async function indexGoProject(targetDir, options = {}) {
  const absTargetDir = validateTargetDir(targetDir)
  const scipGoBin = await findScipGo(options.scipGoPath)
  const outputOption = options.output || null
  const scipOutputPath = resolveScipOutputPath(absTargetDir, outputOption)

  await runScipGo(scipGoBin, absTargetDir, { output: outputOption, timeoutMs: options.timeoutMs })
  const { files, symbolCount } = parseScipResult(scipOutputPath, absTargetDir)

  if (!options.keepOutput) {
    try { fs.unlinkSync(scipOutputPath) } catch { /* already removed ÔÇö safe to ignore */ }
  }

  return {
    files,
    symbolCount,
    scipOutputPath: options.keepOutput ? scipOutputPath : '<cleaned>',
  }
}

module.exports = {
  indexGoProject,
  GoIndexerError,
  validateTargetDir,
  findScipGo,
  parseScipIndex,
}
