{"type":"tool_use","id":"call_87d113eca80f4d1d838e269f","name":"Write","input":{"file_path":"/Users/xin/auto-skills/.claude/worktrees/worker-task-6-mnpf88y2/tracking/git-diff-tracker.js","content":"const { execFile } = require('child_process')
const fs = require('fs')
const path = require('path')

const MAX_LOG_LIMIT = 10000
const MAX_BUFFER = 50 * 1024 * 1024

const GitError = {
  NOT_A_REPO: 'NOT_A_REPO',
  GIT_NOT_INSTALLED: 'GIT_NOT_INSTALLED',
  NO_COMMITS: 'NO_COMMITS',
  UNKNOWN: 'UNKNOWN'
}

function makeGitError(code, message) {
  return { code, message }
}

function execGit(projectPath, args) {
  return new Promise((resolve) => {
    const gitBin = process.platform === 'win32' ? 'git.exe' : 'git'
    execFile(gitBin, args, {
      cwd: projectPath,
      maxBuffer: MAX_BUFFER,
      timeout: 30000
    }, (err, stdout, stderr) => {
      if (err) {
        if (err.code === 'ENOENT') {
          return resolve({ ok: false, error: makeGitError(GitError.GIT_NOT_INSTALLED, 'git is not installed') })
        }
        if (stderr && stderr.includes('not a git repository')) {
          return resolve({ ok: false, error: makeGitError(GitError.NOT_A_REPO, `${projectPath} is not a git repository`) })
        }
        return resolve({ ok: false, error: makeGitError(GitError.UNKNOWN, stderr || err.message) })
      }
      resolve({ ok: true, stdout: stdout.trim() })
    })
  })
}

function safeParseJSON(text, filePath) {
  try {
    return { ok: true, data: JSON.parse(text) }
  } catch (e) {
    console.error(`[git-diff-tracker] Failed to parse JSON in ${filePath}: ${e.message}`)
    return { ok: false, error: e }
  }
}

async function getCurrentHead(projectPath) {
  const isRepo = await execGit(projectPath, ['rev-parse', '--is-inside-work-tree'])
  if (!isRepo.ok) {
    return { ok: false, error: isRepo.error }
  }

  const result = await execGit(projectPath, ['rev-parse', 'HEAD'])
  if (!result.ok) {
    const stderr = result.error.message || ''
    if (stderr.includes('unknown revision') || stderr.includes('HEAD')) {
      return { ok: false, error: makeGitError(GitError.NO_COMMITS, 'repository has no commits yet') }
    }
    return { ok: false, error: result.error }
  }

  return { ok: true, commit: result.stdout }
}

function parseDiffLine(line) {
  if (!line) return null

  const tabIdx = line.indexOf('\t')
  if (tabIdx === -1) return null

  const statusRaw = line.substring(0, tabIdx)
  const rest = line.substring(tabIdx + 1)

  const statusMatch = statusRaw.match(/^([ADMRC])/)
  if (!statusMatch) return null
  const status = statusMatch[1]

  if (status === 'R') {
    const secondTab = rest.indexOf('\t')
    if (secondTab === -1) return null
    const oldPath = rest.substring(0, secondTab)
    const newPath = rest.substring(secondTab + 1)
    return { status, oldPath, newPath }
  }

  return { status, path: rest }
}

async function getChangedFiles(projectPath, baseCommit) {
  const args = ['diff', '--name-status', `${baseCommit}...HEAD`]
  const result = await execGit(projectPath, args)
  if (!result.ok) {
    const errMsg = result.error.message || ''
    if (errMsg.includes('no merge base') || errMsg.includes('unrelated histories')) {
      const allResult = await execGit(projectPath, ['log', '--format=%H', baseCommit])
      if (!allResult.ok) {
        return { ok: false, error: result.error }
      }
      return getChangedFiles(projectPath, allResult.stdout.split('\n').pop())
    }
    return { ok: false, error: result.error }
  }

  const changes = []
  const lines = result.stdout.split('\n')
  for (const line of lines) {
    const parsed = parseDiffLine(line)
    if (!parsed) continue
    changes.push(parsed)
  }

  return { ok: true, changes }
}

async function getChangedFiles(projectPath, baseCommit) {
  const args = ['diff', '--name-status', '-M', `${baseCommit}...HEAD`]
  const result = await execGit(projectPath, args)
  if (!result.ok) {
    const errMsg = result.error.message || ''
    if (errMsg.includes('no merge base') || errMsg.includes('unrelated histories')) {
      const allResult = await execGit(projectPath, ['log', '--format=%H', baseCommit])
      if (!allResult.ok) {
        return { ok: false, error: result.error }
      }
      const oldestCommit = allResult.stdout.split('\n').filter(Boolean).pop()
      if (!oldestCommit) {
        return { ok: true, changes: [] }
      }
      return getChangedFiles(projectPath, oldestCommit)
    }
    return { ok: false, error: result.error }
  }

  const changes = []
  const lines = result.stdout.split('\n')
  for (const line of lines) {
    const parsed = parseDiffLine(line)
    if (!parsed) continue
    changes.push(parsed)
  }

  return { ok: true, changes }
}

function getLastIndexedCommit(logFilePath) {
  if (!fs.existsSync(logFilePath)) {
    return null
  }

  const lines = readLogLines(logFilePath, 1)
  if (lines.length === 0) return null

  const parsed = safeParseJSON(lines[0], logFilePath)
  if (!parsed.ok) return null
  return parsed.data.commit || null
}

function saveIndexedCommit(logFilePath, commit) {
  const dir = path.dirname(logFilePath)
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true })
  }
  const entry = JSON.stringify({
    commit,
    timestamp: new Date().toISOString()
  })
  fs.appendFileSync(logFilePath, entry + '\n')
}

function readLogLines(logFilePath, limit) {
  const safeLimit = Math.min(
    Math.max(1, Math.floor(Number(limit)) || 10),
    MAX_LOG_LIMIT
  )

  if (!fs.existsSync(logFilePath)) return []

  const content = fs.readFileSync(logFilePath, 'utf-8')
  const lines = content.split('\n').filter(Boolean)
  const entries = []
  const start = Math.max(0, lines.length - safeLimit)

  for (let i = start; i < lines.length; i++) {
    const result = safeParseJSON(lines[i], `${logFilePath}:${i + 1}`)
    if (result.ok) {
      entries.push(result.data)
    }
  }

  return entries
}

async function getFilesToIndex(projectPath, logFilePath) {
  const headResult = await getCurrentHead(projectPath)
  if (!headResult.ok) {
    return { ok: false, error: headResult.error }
  }

  const currentHead = headResult.commit
  const lastIndexed = getLastIndexedCommit(logFilePath)

  if (lastIndexed === currentHead) {
    return { ok: true, files: [], commit: currentHead }
  }

  let changes
  if (!lastIndexed) {
    const result = await execGit(projectPath, ['ls-files'])
    if (!result.ok) {
      return { ok: false, error: result.error }
    }
    changes = result.stdout.split('\n').filter(Boolean).map(filePath => ({
      status: 'A',
      path: filePath
    }))
  } else {
    const diffResult = await getChangedFiles(projectPath, lastIndexed)
    if (!diffResult.ok) {
      return { ok: false, error: diffResult.error }
    }
    changes = diffResult.changes
  }

  const files = changes.map(change => {
    if (change.status === 'D') {
      return { action: 'delete', path: change.path || change.oldPath }
    }
    if (change.status === 'R') {
      return [
        { action: 'delete', path: change.oldPath },
        { action: 'index', path: change.newPath }
      ]
    }
    return { action: 'index', path: change.path }
  }).flat()

  return { ok: true, files, commit: currentHead }
}

function markIndexed(logFilePath, commit) {
  saveIndexedCommit(logFilePath, commit)
}

module.exports = {
  getFilesToIndex,
  markIndexed,
  getCurrentHead,
  getChangedFiles,
  getLastIndexedCommit,
  readLogLines,
  GitError
}
"}}

