   110Ôćĺ
   111Ôćĺ  const changes = []
   112Ôćĺ  const lines = result.stdout.split('\n')
   113Ôćĺ  for (const line of lines) {
   114Ôćĺ    const parsed = parseDiffLine(line)
   115Ôćĺ    if (!parsed) continue
   116Ôćĺ    changes.push(parsed)
   117Ôćĺ  }
   118Ôćĺ
   119Ôćĺ  return { ok: true, changes }
   120Ôćĺ}
   121Ôćĺ
   122Ôćĺfunction getLastIndexedCommit(logFilePath) {
   123Ôćĺ  const entries = readLogLines(logFilePath, 1)
   124Ôćĺ  if (entries.length === 0) return null
   125Ôćĺ  return entries[entries.length - 1].commit || null
   126Ôćĺ}
   127Ôćĺ
   128Ôćĺfunction saveIndexedCommit(logFilePath, commit) {
   129Ôćĺ  const dir = path.dirname(logFilePath)
   130Ôćĺ  if (!fs.existsSync(dir)) {
   131Ôćĺ    fs.mkdirSync(dir, { recursive: true })
   132Ôćĺ  }
   133Ôćĺ  const entry = JSON.stringify({
   134Ôćĺ    commit,
   135Ôćĺ    timestamp: new Date().toISOString()
   136Ôćĺ  })
   137Ôćĺ  fs.appendFileSync(logFilePath, entry + '\n')
