   139Ôćĺ
   140Ôćĺfunction readLogLines(logFilePath, limit) {
   141Ôćĺ  const safeLimit = Math.min(
   142Ôćĺ    Math.max(1, Math.floor(Number(limit)) || 10),
   143Ôćĺ    MAX_LOG_LIMIT
   144Ôćĺ  )
   145Ôćĺ
   146Ôćĺ  if (!fs.existsSync(logFilePath)) return []
   147Ôćĺ
   148Ôćĺ  const content = fs.readFileSync(logFilePath, 'utf-8')
   149Ôćĺ  const lines = content.split('\n').filter(Boolean)
   150Ôćĺ  const entries = []
   151Ôćĺ  const start = Math.max(0, lines.length - safeLimit)
   152Ôćĺ
   153Ôćĺ  for (let i = start; i < lines.length; i++) {
   154Ôćĺ    const result = safeParseJSON(lines[i], `${logFilePath}:${i + 1}`)
   155Ôćĺ    if (result.ok) {
   156Ôćĺ      entries.push(result.data)
   157Ôćĺ    }
   158Ôćĺ  }
   159Ôćĺ
   160Ôćĺ  return entries
   161Ôćĺ}
   162Ôćĺ
   163Ôćĺasync function getFilesToIndex(projectPath, logFilePath) {
   164Ôćĺ  const headResult = await getCurrentHead(projectPath)
   165Ôćĺ  if (!headResult.ok) {
   166Ôćĺ    return { ok: false, error: headResult.error }
   167Ôćĺ  }
   168Ôćĺ
   169Ôćĺ  const currentHead = headResult.commit
   170Ôćĺ  const lastIndexed = getLastIndexedCommit(logFilePath)
   171Ôćĺ
   172Ôćĺ  if (lastIndexed === currentHead) {
   173Ôćĺ    return { ok: true, files: [], commit: currentHead }
   174Ôćĺ  }
   175Ôćĺ
   176Ôćĺ  let changes
   177Ôćĺ  if (!lastIndexed) {
   178Ôćĺ    const result = await execGit(projectPath, ['ls-files'])
   179Ôćĺ    if (!result.ok) {
   180Ôćĺ      return { ok: false, error: result.error }
   181Ôćĺ    }
   182Ôćĺ    changes = result.stdout.split('\n').filter(Boolean).map(filePath => ({
   183Ôćĺ      status: 'A',
   184Ôćĺ      path: filePath
   185Ôćĺ    }))
   186Ôćĺ  } else {
   187Ôćĺ    const diffResult = await getChangedFiles(projectPath, lastIndexed)
   188Ôćĺ    if (!diffResult.ok) {
   189Ôćĺ      return { ok: false, error: diffResult.error }
   190Ôćĺ    }
   191Ôćĺ    changes = diffResult.changes
   192Ôćĺ  }
   193Ôćĺ
   194Ôćĺ  const files = changes.map(change => {
   195Ôćĺ    if (change.status === 'D') {
   196Ôćĺ      return { action: 'delete', path: change.path || change.oldPath }
   197Ôćĺ    }
   198Ôćĺ    if (change.status === 'R') {
   199Ôćĺ      return [
   200Ôćĺ        { action: 'delete', path: change.oldPath },
   201Ôćĺ        { action: 'index', path: change.newPath }
   202Ôćĺ      ]
   203Ôćĺ    }
   204Ôćĺ    return { action: 'index', path: change.path }
   205Ôćĺ  }).flat()
   206Ôćĺ
   207Ôćĺ  return { ok: true, files, commit: currentHead }
   208Ôćĺ}
   209Ôćĺ
   210Ôćĺfunction markIndexed(logFilePath, commit) {
   211Ôćĺ  saveIndexedCommit(logFilePath, commit)
   212Ôćĺ}
   213Ôćĺ
   214Ôćĺmodule.exports = {
   215Ôćĺ  getFilesToIndex,
   216Ôćĺ  markIndexed,
   217Ôćĺ  getCurrentHead,
   218Ôćĺ  getChangedFiles,
   219Ôćĺ  getLastIndexedCommit,
   220Ôćĺ  readLogLines,
   221Ôćĺ  GitError
   222Ôćĺ}
