import { execSync } from "child_process";
import { existsSync, statSync } from "fs";
import { join, relative, resolve } from "path";
import { fileURLToPath } from "url";

const __filename = fileURLToPath(import.meta.url);

interface IndexEntry {
  path: string;
  mtime: number;
  size: number;
}

interface IndexState {
  version: number;
  lastIndexed: number;
  files: Record<string, IndexEntry>;
}

const INDEX_VERSION = 1;
const STATE_FILE = ".fg-index-state.json";

function log(message: string): void {
  console.error(`[fg-index-hook] ${message}`);
}

function findGitRoot(startPath: string): string | null {
  let current = resolve(startPath);
  const root = resolve("/");

  while (current !== root) {
    if (existsSync(join(current, ".git"))) {
      return current;
    }
    current = resolve(current, "..");
  }
  return null;
}

function detectProjectType(projectPath: string): "typescript" | "go" | null {
  if (existsSync(join(projectPath, "tsconfig.json"))) {
    return "typescript";
  }
  if (existsSync(join(projectPath, "go.mod"))) {
    return "go";
  }
  return null;
}

function getChangedFiles(projectPath: string, state: IndexState | null): string[] {
  const changed: string[] = [];
  const projectType = detectProjectType(projectPath);

  if (!projectType) {
    log("No project type detected");
    return changed;
  }

  const extensions = projectType === "typescript" ? [".ts", ".tsx", ".js", ".jsx"] : [".go"];

  try {
    const gitOutput = execSync("git ls-files", {
      cwd: projectPath,
      encoding: "utf-8",
    });

    const trackedFiles = gitOutput.trim().split("\n").filter(Boolean);

    for (const file of trackedFiles) {
      const fullPath = join(projectPath, file);
      if (!existsSync(fullPath)) continue;

      const ext = file.slice(file.lastIndexOf("."));
      if (!extensions.includes(ext)) continue;

      const stats = statSync(fullPath);
      const cached = state?.files[file];

      if (!cached || cached.mtime !== stats.mtimeMs || cached.size !== stats.size) {
        changed.push(file);
      }
    }
  } catch (err) {
    log(`Git ls-files failed: ${err instanceof Error ? err.message : String(err)}`);
  }

  return changed;
}

function loadState(projectPath: string): IndexState | null {
  const statePath = join(projectPath, STATE_FILE);
  if (!existsSync(statePath)) return null;

  try {
    const content = execSync(`cat "${statePath}"`, { encoding: "utf-8" });
    const parsed = JSON.parse(content) as IndexState;
    if (parsed.version !== INDEX_VERSION) return null;
    return parsed;
  } catch {
    return null;
  }
}

function saveState(projectPath: string, state: IndexState): void {
  const statePath = join(projectPath, STATE_FILE);
  try {
    execSync(`echo '${JSON.stringify(state, null, 2)}' > "${statePath}"`);
  } catch (err) {
    log(`Failed to save state: ${err instanceof Error ? err.message : String(err)}`);
  }
}

function updateFileState(projectPath: string, state: IndexState, files: string[]): void {
  for (const file of files) {
    const fullPath = join(projectPath, file);
    try {
      const stats = statSync(fullPath);
      state.files[file] = {
        path: file,
        mtime: stats.mtimeMs,
        size: stats.size,
      };
    } catch {
      delete state.files[file];
    }
  }
  state.lastIndexed = Date.now();
}

function runIncrementalIndex(projectPath: string, changedFiles: string[]): boolean {
  if (changedFiles.length === 0) {
    log("No changed files to index");
    return true;
  }

  log(`Indexing ${changedFiles.length} changed file(s)`);

  const projectType = detectProjectType(projectPath);
  if (!projectType) {
    log("Cannot determine project type");
    return false;
  }

  const indexerCmd = projectType === "typescript" ? "scip-typescript" : "scip-go";
  const indexerArgs = ["index", "--output", "index.json"];

  try {
    execSync(`${indexerCmd} ${indexerArgs.join(" ")}`, {
      cwd: projectPath,
      stdio: ["pipe", "pipe", "pipe"],
