function main(): number {
  const startPath = process.argv[2] || process.cwd();

  log(`Starting incremental index from: ${startPath}`);

  const projectRoot = findGitRoot(startPath);
  if (!projectRoot) {
    log("No git repository found");
    return 1;
  }

  log(`Detected project root: ${projectRoot}`);

  const projectType = detectProjectType(projectRoot);
  if (!projectType) {
    log("No supported project type detected (tsconfig.json or go.mod)");
    return 1;
  }

  log(`Project type: ${projectType}`);

  const state = loadState(projectRoot) || {
    version: INDEX_VERSION,
    lastIndexed: 0,
    files: {},
  };

  const changedFiles = getChangedFiles(projectRoot, state);

  if (changedFiles.length === 0) {
    log("All files up to date");
    return 0;
  }

  log(`Found ${changedFiles.length} changed file(s)`);
  for (const file of changedFiles.slice(0, 5)) {
    log(`  - ${file}`);
  }
  if (changedFiles.length > 5) {
    log(`  ... and ${changedFiles.length - 5} more`);
  }

  const success = runIncrementalIndex(projectRoot, changedFiles);

  if (success) {
    updateFileState(projectRoot, state, changedFiles);
    saveState(projectRoot, state);
    log(`Index updated at ${new Date().toISOString()}`);
    return 0;
  }

  return 1;
}

process.exit(main());
